import React, { useState } from 'react';

const App = () => {
  const [tasks, setTasks] = useState([]);
  const [newTask, setNewTask] = useState('');
  const [daysLeft, setDaysLeft] = useState(0);

  const handleSubmit = (e) => {
    e.preventDefault();
    const newTaskObj = {
      name: newTask,
      completed: false,
      dueDate: '2024-01-01'
    };
    setTasks([...tasks, newTaskObj]);
    setNewTask('');
  };

  const handleDelete = (index) => {
    setTasks(tasks.filter((task, i) => i !== index));
  };

  const handleCompleteToday = (index) => {
    const newTasks = tasks.map((task, i) => i === index ? {
      ...task,
      completed: true
    } : task);
    setTasks(newTasks);
  };

  const calculateDaysLeft = () => {
    const today = new Date();
    const dueDate = new Date('2024-01-01');
    const diffTime = dueDate.getTime() - today.getTime();
    return Math.ceil(diffTime / (1000 * 60 * 60 * 24));
  };

  return (
    <div className="min-h-screen bg-[#090a0f] text-white p-4 flex items-center justify-center">
      <div className="w-1/2 bg-white p-4 rounded shadow">
        <h2 className="text-lg font-bold mb-2">Tasks</h2>
        <ul className="list-disc pl-4 mb-4">
          {tasks.map((task, index) => (
            <li key={index} className="mb-2">
              <span className="mr-2">{task.name}</span>
              <button className="bg-green-500 hover:bg-green-700 text-white font-bold py-1 px-2 rounded" onClick={() => handleCompleteToday(index)}>Complete Today</button>
              <button className="bg-red-500 hover:bg-red-700 text-white font-bold py-1 px-2 rounded" onClick={() => handleDelete(index)}>Delete</button>
            </li>
          ))}
        </ul>
        <form onSubmit={handleSubmit} className="mb-4">
          <input
            type="text"
            value={newTask}
            onChange={(e) => setNewTask(e.target.value)}
            placeholder="Add new task"
            className="p-2 w-full border border-gray-300 rounded"
          />
          <button className="bg-blue-500 hover:bg-blue-700 text-white font-bold py-1 px-2 rounded" type="submit">Add Task</button>
        </form>
        <p className="text-lg font-bold mb-2">Days Left: {calculateDaysLeft()}</p>
      </div>
    </div>
  );
};

export default App;
